// Generate a GCS signed URL for the video clip
// CRITICAL: expiry must be >= 3600 seconds
// Instagram takes 30-120 seconds to download the video after container creation.
// A short-lived URL (< 60s) will return 403 during Instagram's download phase.

const items = $input.all();
const item = items[0];
const { gcs_bucket, clip_gcs_path, content_bank_id } = item.json;

// If the clip already has a signed_url stored, use it (saves a GCS API call)
if (item.json.best_clip && item.json.best_clip.signed_url) {
  return [{
    json: {
      ...item.json,
      video_url: item.json.best_clip.signed_url
    }
  }];
}

// Build GCS Signed URL via GCS XML API (v4 HMAC signature)
// NOTE: For production, use a GCS service account with roles/storage.objectViewer
// and generate signed URLs via the GCS REST API or a Cloud Function.
// For simplicity in v1, if the video is in a public GCS bucket, use the public URL directly.

const gcsBucket = gcs_bucket || process.env.GCS_BUCKET || 'YOUR_GCS_BUCKET_NAME';
const gcsPath = clip_gcs_path || 'path/to/clip.mp4';

// Use public GCS URL as fallback (ensure bucket objects are public or use signed URL service)
// For signed URLs: integrate with GCS Signed URL API via HTTP Request node (see workflow notes)
const videoUrl = `https://storage.googleapis.com/${gcsBucket}/${gcsPath}`;

// NOTE: To use actual signed URLs (recommended for private buckets):
// 1. Deploy a Cloud Function that accepts {bucket, path} and returns a signed URL
// 2. Replace the HTTP Request node in Step 3c with a call to that function
// 3. The signed URL will have ?X-Goog-Expires=3600 parameter automatically

return [{
  json: {
    ...item.json,
    video_url: videoUrl,
    signed_url_expiry: 3600,
    signed_url_generated_at: new Date().toISOString()
  }
}];
